37	export function renderWithProviders(
38	  ui: ReactElement,
39	  options?: Omit<RenderOptions, "wrapper"> & { route?: string; initialEntries?: string[] },
40	) {
41	  const { route, initialEntries, ...renderOptions } = options ?? {};
42	
43	  function Wrapper({ children }: { children: ReactNode }) {
44	    return (
45	      <TestProviders initialEntries={initialEntries ?? (route ? [route] : undefined)}>
46	        {children}
47	      </TestProviders>
48	    );
49	  }
50	
51	  return render(ui, { wrapper: Wrapper, ...renderOptions });
52	}
