8	}
9	
10	describe("ErrorBoundary", () => {
11	  // Suppress React error boundary console noise
12	  const originalError = console.error;
13	  beforeEach(() => { console.error = vi.fn(); });
14	  afterEach(() => { console.error = originalError; });
15	
16	  it("renders children when no error", () => {
17	    render(
18	      <ErrorBoundary>
19	        <div>hello</div>
20	      </ErrorBoundary>,
21	    );
22	    expect(screen.getByText("hello")).toBeInTheDocument();
23	  });
24	
25	  it("renders error message when child throws", () => {
26	    render(
27	      <ErrorBoundary>
28	        <ThrowingChild shouldThrow={true} />
29	      </ErrorBoundary>,
30	    );
31	    expect(screen.getByText("Something went wrong")).toBeInTheDocument();
32	    expect(screen.getByText("test crash")).toBeInTheDocument();
33	  });
34	
35	  it("shows try again button", () => {
36	    render(
37	      <ErrorBoundary>
38	        <ThrowingChild shouldThrow={true} />
39	      </ErrorBoundary>,
40	    );
41	
42	    expect(screen.getByText("Something went wrong")).toBeInTheDocument();
43	    expect(screen.getByText("Try again")).toBeInTheDocument();
44	  });
45	
46	  it("renders custom fallback when provided", () => {
47	    render(
48	      <ErrorBoundary fallback={<div>custom error view</div>}>
49	        <ThrowingChild shouldThrow={true} />
50	      </ErrorBoundary>,
