4	describe("formatProbability", () => {
5	  it("formats 0.65 as 65.0%", () => expect(formatProbability(0.65)).toBe("65.0%"));
6	  it("formats 0.01 as 1.0%", () => expect(formatProbability(0.01)).toBe("1.0%"));
7	  it("formats 0.999 as 99.9%", () => expect(formatProbability(0.999)).toBe("99.9%"));
