9	
10	describe("formatCurrency", () => {
11	  it("formats large numbers with K suffix", () => expect(formatCurrency(45000)).toBe("45.0K"));
12	  it("formats millions with M suffix", () => expect(formatCurrency(1500000)).toBe("1.5M"));
13	  it("formats small numbers with decimals", () => expect(formatCurrency(42.5)).toBe("42.50"));
14	  it("formats negative thousands with K suffix", () => expect(formatCurrency(-45000)).toBe("-45.0K"));
15	  it("formats negative millions with M suffix", () => expect(formatCurrency(-1500000)).toBe("-1.5M"));
16	});
17	
18	describe("truncateHash", () => {
19	  it("truncates sha256 hashes", () => {
20	    expect(truncateHash("sha256:abcdef0123456789")).toBe("sha256:abcdef01…");
21	  });
22	  it("leaves short strings alone", () => {
23	    expect(truncateHash("short")).toBe("short");
24	  });
25	  it("truncates sha256 hashes with custom length", () => {
26	    expect(truncateHash("sha256:abcdef0123456789", 4)).toBe("sha256:abcd…");
27	  });
28	  it("truncates non-sha256 long strings", () => {
29	    expect(truncateHash("abcdef0123456789")).toBe("abcdef01…");
30	  });
31	});
32	
33	describe("formatRelativeTime", () => {
34	  beforeEach(() => {
35	    vi.useFakeTimers();
36	    vi.setSystemTime(new Date("2025-06-15T12:00:00Z"));
37	  });
38	  afterEach(() => {
39	    vi.useRealTimers();
40	  });
41	
42	  it("returns 'just now' for less than 1 minute ago", () => {
43	    expect(formatRelativeTime("2025-06-15T11:59:30Z")).toBe("just now");
44	  });
45	  it("returns minutes ago", () => {
46	    expect(formatRelativeTime("2025-06-15T11:45:00Z")).toBe("15m ago");
47	  });
48	  it("returns hours ago", () => {
49	    expect(formatRelativeTime("2025-06-15T09:00:00Z")).toBe("3h ago");
50	  });
51	  it("returns days ago", () => {
52	    expect(formatRelativeTime("2025-06-13T12:00:00Z")).toBe("2d ago");
53	  });
54	});
55	
56	describe("timeUntil", () => {
57	  beforeEach(() => {
58	    vi.useFakeTimers();
59	    vi.setSystemTime(new Date("2025-06-15T12:00:00Z"));
60	  });
61	  afterEach(() => {
62	    vi.useRealTimers();
63	  });
64	
65	  it("returns 'expired' for past dates", () => {
66	    expect(timeUntil("2025-06-15T11:00:00Z")).toBe("expired");
67	  });
68	  it("returns hours and minutes remaining", () => {
69	    expect(timeUntil("2025-06-15T14:30:00Z")).toBe("2h 30m");
70	  });
71	  it("returns days and hours remaining", () => {
72	    expect(timeUntil("2025-06-17T18:00:00Z")).toBe("2d 6h");
73	  });
74	});
